// Converte o valor da chave "numero" do objeto JSON "$json" em uma string
var wpp = $json["numero"].toString();

// Remove todos os caracteres que não sejam dígitos (0-9) da string "wpp" e armazena o resultado em "fwpp"
var fwpp = wpp.replace(/[^0-9]+/g, '');

// Se o comprimento de "fwpp" for maior que 11, remove os dois primeiros caracteres
if (fwpp.length > 11) {
fwpp = fwpp.substring(2, fwpp.length);
}

// Obtém os dois primeiros dígitos de "fwpp" e armazena em "ddd"
var ddd = fwpp.substring(0, 2);

// Se o comprimento de "fwpp" for igual a 11, verifica se o valor de "ddd" é maior ou igual a 31
if (fwpp.length == 11) {
if (parseInt(ddd) >= 31) {

// Remove o terceiro caractere de "fwpp" (índice 3) e concatena com o restante
fwpp = fwpp.substring(0, 3) + fwpp.substring(4, fwpp.length);
}
}

// Se o comprimento de "fwpp" for igual a 10 e o valor de "ddd" for menor que 30
if (fwpp.length == 10) {
if (parseInt(ddd) < 30) {

// Remove os dois primeiros caracteres de "fwpp", acrescenta '9' e concatena com o restante
var num = fwpp.substring(2);
fwpp = ddd + '9' + num;
}
}

// Adiciona '55' no início de "fwpp" se seu comprimento for menor ou igual a 11
if (fwpp.length <= 11) {
fwpp = '55' + fwpp;
}

// Atribui o valor de "fwpp" à chave "fwpp" no objeto JSON "$input.item"
$input.item.json.fwpp = fwpp;

// Retorna o objeto JSON modificado "$input.item"
return $input.item;

